import React from "react";
import { NavLink, useNavigate } from "react-router-dom";

function Navbar() {
  const navigate = useNavigate();

  const handleLogout = () => {
    localStorage.removeItem("user");
    navigate("/login");
  };

  return (
    <header style={styles.navbar}>

      {/* Logo */}
      <div style={styles.logoContainer} onClick={() => navigate("/")}>
        <img
          src="https://cdn-icons-png.flaticon.com/512/2966/2966485.png"
          alt="logo"
          style={styles.logoImg}
        />
        <h2 style={styles.logoText}>DocBook</h2>
      </div>

      {/* Nav Links */}
      <nav>
        <ul style={styles.navLinks}>

          <li>
            <NavLink to="/" style={styles.link}>
              Home
            </NavLink>
          </li>

          <li>
            <NavLink to="/doctors" style={styles.link}>
              Doctors
            </NavLink>
          </li>

          <li>
            <NavLink to="/appointments" style={styles.link}>
              My Appointments
            </NavLink>
          </li>

          <li>
            <NavLink to="/profile" style={styles.link}>
              Profile
            </NavLink>
          </li>

          <li style={styles.logout} onClick={handleLogout}>
            Logout
          </li>

        </ul>
      </nav>

    </header>
  );
}

export default Navbar;
